SET time_zone = "+00:00";CREATE TABLE IF NOT EXISTS SUBSCRIPTION_PLANS (id              INT PRIMARY KEY NOT NULL AUTO_INCREMENT,name            VARCHAR(50)     NOT NULL,price_monthly   DECIMAL(10,2)   NOT NULL,features_json   JSON            NULL,created_at      TIMESTAMP       NOT NULL DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ciCOMMENT='Subscription tier definitions (Basic, Pro, Premium)';CREATE TABLE IF NOT EXISTS MP_SUBSCRIPTIONS (id          INT         NOT NULL AUTO_INCREMENT,mp_id       INT         NOT NULL,plan_id     INT         NOT NULL,status      VARCHAR(20) NOT NULL DEFAULT 'active'COMMENT 'active | suspended | cancelled',start_date  DATE        NOT NULL,end_date    DATE        NULL,created_at  TIMESTAMP   NOT NULL DEFAULT CURRENT_TIMESTAMP,PRIMARY KEY (id),KEY idx_mp_id    (mp_id),KEY idx_status   (status),KEY idx_end_date (end_date),CONSTRAINT fk_mpsub_plan FOREIGN KEY (plan_id)REFERENCES SUBSCRIPTION_PLANS (id) ON UPDATE CASCADE,CONSTRAINT fk_mpsub_mp FOREIGN KEY (mp_id)REFERENCES MPs (id) ON UPDATE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ciCOMMENT='MP subscription records — plan, dates, and status';CREATE TABLE IF NOT EXISTS PRESS_ACCOUNTS (id              INT   PRIMARY KEY  NOT NULL AUTO_INCREMENT,org_name        VARCHAR(200) UNIQUE KEY   NOT NULL,contact_name    VARCHAR(200)    NULL,email           VARCHAR(200)    NOT NULL,tier            VARCHAR(20)     NULL,created_at      TIMESTAMP       NOT NULL DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ciCREATE TABLE IF NOT EXISTS PRESS_EXPORTS (id                  INT  PRIMARY KEY NOT NULL AUTO_INCREMENT,press_account_id    INT             NOT NULL,export_type         VARCHAR(50)     NOT NULL,filters_json        JSON            NULL,file_url            VARCHAR(500)    NULL,created_at          TIMESTAMP       NOT NULL DEFAULT CURRENT_TIMESTAMP,KEY idx_press_export_account (press_account_id),KEY idx_press_export_type    (export_type),CONSTRAINT fk_export_press FOREIGN KEY (press_account_id)REFERENCES PRESS_ACCOUNTS (id) ON UPDATE CASCADE ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ciDELIMITER $$DROP PROCEDURE IF EXISTS sp_GetAllSubscriptionPlans $$CREATE PROCEDURE sp_GetAllSubscriptionPlans()BEGINSELECT * FROM   SUBSCRIPTION_PLANSORDER  BY price_monthly ASC;END $$DROP PROCEDURE IF EXISTS sp_GetSubscriptionPlan $$CREATE PROCEDURE sp_GetSubscriptionPlan(IN p_plan_id INT)BEGINSELECT id,name,price_monthly,features_json,created_atFROM   SUBSCRIPTION_PLANSWHERE  id = p_plan_id;END $$DROP PROCEDURE IF EXISTS sp_InsertSubscriptionPlan $$CREATE PROCEDURE sp_InsertSubscriptionPlan(IN  p_name          VARCHAR(50),IN  p_price_monthly DECIMAL(10,2),IN  p_features_json JSON,OUT p_new_id        INT)BEGININSERT INTO SUBSCRIPTION_PLANS (name, price_monthly, features_json)VALUES (p_name, p_price_monthly, p_features_json);    SET p_new_id = LAST_INSERT_ID();END $$DROP PROCEDURE IF EXISTS sp_UpdateSubscriptionPlan $$CREATE PROCEDURE sp_UpdateSubscriptionPlan(IN p_plan_id        INT,IN p_price_monthly  DECIMAL(10,2),IN p_features_json  JSON)BEGINUPDATE SUBSCRIPTION_PLANSSET    price_monthly = p_price_monthly,features_json = p_features_jsonWHERE  id = p_plan_id;    SELECT ROW_COUNT() AS rows_affected;END $$DROP PROCEDURE IF EXISTS sp_SubscribeMP $$CREATE PROCEDURE sp_SubscribeMP(IN  p_mp_id      INT,IN  p_plan_id    INT,IN  p_start_date DATE,IN  p_end_date   DATE,OUT p_new_id     INT)BEGINUPDATE MP_SUBSCRIPTIONSSET    status = 'cancelled'WHERE  mp_id  = p_mp_idAND  status = 'active';    INSERT INTO MP_SUBSCRIPTIONS (mp_id, plan_id, status, start_date, end_date)    VALUES (p_mp_id, p_plan_id, 'active', p_start_date, p_end_date);    SET p_new_id = LAST_INSERT_ID();END $$DROP PROCEDURE IF EXISTS sp_GetMPSubscription $$CREATE PROCEDURE sp_GetMPSubscription(IN p_mp_id INT)BEGINSELECT s.id,s.mp_id,s.plan_id,p.name           AS plan_name,p.price_monthly,p.features_json,s.status,s.start_date,s.end_date,s.created_atFROM   MP_SUBSCRIPTIONS   sJOIN   SUBSCRIPTION_PLANS p ON p.id = s.plan_idWHERE  s.mp_id  = p_mp_idAND  s.status = 'active';END $$DROP PROCEDURE IF EXISTS sp_UpdateSubscriptionStatus $$CREATE PROCEDURE sp_UpdateSubscriptionStatus(IN p_subscription_id INT,IN p_status          VARCHAR(20))BEGINUPDATE MP_SUBSCRIPTIONSSET    status = p_statusWHERE  id = p_subscription_id;    SELECT ROW_COUNT() AS rows_affected;END $$DROP PROCEDURE IF EXISTS sp_GetExpiringSubscriptions $$CREATE PROCEDURE sp_GetExpiringSubscriptions()BEGINSELECT s.id,s.mp_id,p.name           AS plan_name,s.end_date,DATEDIFF(s.end_date, CURDATE()) AS days_remaining,s.statusFROM   MP_SUBSCRIPTIONS   sJOIN   SUBSCRIPTION_PLANS p ON p.id = s.plan_idWHERE  s.status   = 'active'AND  s.end_date BETWEEN CURDATE()AND DATE_ADD(CURDATE(), INTERVAL 7 DAY)ORDER  BY s.end_date ASC;END $$DROP PROCEDURE IF EXISTS sp_InsertPressAccount $$CREATE PROCEDURE sp_InsertPressAccount(IN  p_org_name      VARCHAR(200),IN  p_contact_name  VARCHAR(200),IN  p_email         VARCHAR(200),IN  p_tier          VARCHAR(20),OUT p_new_id        INT)BEGININSERT INTO PRESS_ACCOUNTS (org_name, contact_name, email, tier)VALUES (p_org_name, p_contact_name, p_email, p_tier);    SET p_new_id = LAST_INSERT_ID();END $$DROP PROCEDURE IF EXISTS sp_GetPressAccount $$CREATE PROCEDURE sp_GetPressAccount(IN p_press_id INT)BEGINSELECT *FROM   PRESS_ACCOUNTSWHERE  id = p_press_id;END $$DROP PROCEDURE IF EXISTS sp_GetAllPressAccounts $$CREATE PROCEDURE sp_GetAllPressAccounts(IN p_tier VARCHAR(20))BEGINSELECT id,org_name,contact_name,email,tier,created_atFROM   PRESS_ACCOUNTSWHERE  (p_tier IS NULL OR tier = p_tier)ORDER  BY org_name ASC;END $$DROP PROCEDURE IF EXISTS sp_LogPressExport $$CREATE PROCEDURE sp_LogPressExport(IN  p_press_account_id  INT,IN  p_export_type       VARCHAR(50),IN  p_filters_json      JSON,IN  p_file_url          VARCHAR(500),OUT p_new_id            INT)BEGININSERT INTO PRESS_EXPORTS (press_account_id, export_type, filters_json, file_url)VALUES (p_press_account_id, p_export_type, p_filters_json, p_file_url);    SET p_new_id = LAST_INSERT_ID();END $$DROP PROCEDURE IF EXISTS sp_GetPressExportsByAccount $$CREATE PROCEDURE sp_GetPressExportsByAccount(IN p_press_account_id INT)BEGINSELECT id,press_account_id,export_type,filters_json,file_url,created_atFROM   PRESS_EXPORTSWHERE  press_account_id = p_press_account_idORDER  BY created_at DESC;END $$DROP PROCEDURE IF EXISTS sp_GetMPScorecard $$CREATE PROCEDURE sp_GetMPScorecard(IN p_mp_id INT)BEGINDECLARE v_total_issues        INT           DEFAULT 0;DECLARE v_resolved_issues     INT           DEFAULT 0;DECLARE v_resolution_rate     DECIMAL(5,2)  DEFAULT 0.00;    DECLARE v_avg_response_hours  DECIMAL(10,2) DEFAULT 0.00;    DECLARE v_response_score      DECIMAL(5,2)  DEFAULT 0.00;    DECLARE v_total_promises      INT           DEFAULT 0;    DECLARE v_delivered_promises  INT           DEFAULT 0;    DECLARE v_promise_rate        DECIMAL(5,2)  DEFAULT 0.00;    DECLARE v_overall_score       DECIMAL(5,2)  DEFAULT 0.00;    SELECT COUNT(*) INTO v_total_issues    FROM   ISSUES WHERE mp_id = p_mp_id;    SELECT COUNT(*) INTO v_resolved_issues    FROM   ISSUES WHERE mp_id = p_mp_id AND status = 'resolved';    IF v_total_issues > 0 THEN        SET v_resolution_rate =            ROUND((v_resolved_issues / v_total_issues) * 100, 2);    END IF;    -- Average response time    SELECT ROUND(AVG(TIMESTAMPDIFF(HOUR, i.created_at, fu.first_update_at)), 2)    INTO   v_avg_response_hours    FROM   ISSUES i    JOIN (        SELECT issue_id, MIN(created_at) AS first_update_at        FROM   ISSUE_UPDATES        GROUP BY issue_id    ) fu ON fu.issue_id = i.id    WHERE  i.mp_id = p_mp_id;    -- Convert to 0-100 score    IF v_avg_response_hours IS NOT NULL AND v_avg_response_hours > 0 THEN        IF v_avg_response_hours <= 24 THEN            SET v_response_score = 100.00;        ELSE            SET v_response_score = GREATEST(0.00,                ROUND(100 - ((v_avg_response_hours - 24) / 24) * 10, 2));        END IF;    END IF;    -- Promise delivery rate    SELECT COUNT(*) INTO v_total_promises    FROM   PROMISES WHERE mp_id = p_mp_id;    SELECT COUNT(*) INTO v_delivered_promises    FROM   PROMISES WHERE mp_id = p_mp_id AND status = 'delivered';    IF v_total_promises > 0 THEN        SET v_promise_rate =            ROUND((v_delivered_promises / v_total_promises) * 100, 2);    END IF;    -- Weighted overall score    SET v_overall_score = ROUND(        (v_resolution_rate * 0.40)      + (v_response_score  * 0.30)      + (v_promise_rate    * 0.30), 2);    SELECT        p_mp_id                           AS mp_id,        v_total_issues                    AS total_issues,        v_resolved_issues                 AS resolved_issues,        v_resolution_rate                 AS resolution_rate_pct,        COALESCE(v_avg_response_hours, 0) AS avg_response_hours,        v_response_score                  AS response_score,        v_total_promises                  AS total_promises,        v_delivered_promises              AS delivered_promises,        v_promise_rate                    AS promise_delivery_rate_pct,        v_overall_score                   AS overall_score;END $$DROP PROCEDURE IF EXISTS sp_GetMPRankings $$CREATE PROCEDURE sp_GetMPRankings()BEGINSELECTi.mp_id,COUNT(i.id)                                                         AS total_issues,SUM(CASE WHEN i.status = 'resolved' THEN 1 ELSE 0 END)             AS resolved_issues,ROUND(SUM(CASE WHEN i.status = 'resolved' THEN 1 ELSE 0 END)/ NULLIF(COUNT(i.id), 0) * 100, 2)                                                                AS resolution_rate_pct,ROUND(AVG(TIMESTAMPDIFF(HOUR, i.created_at, fu.first_update_at)), 2)                                                               AS avg_response_hours,ROUND(SUM(CASE WHEN pr.status = 'delivered' THEN 1 ELSE 0 END)/ NULLIF(COUNT(DISTINCT pr.id), 0) * 100, 2)                                                                AS promise_delivery_rate_pct,ROUND(( ROUND(SUM(CASE WHEN i.status = 'resolved' THEN 1 ELSE 0 END)/ NULLIF(COUNT(i.id), 0) * 100, 2) * 0.40 )+ ( GREATEST(0, LEAST(100,CASEWHEN AVG(TIMESTAMPDIFF(HOUR, i.created_at, fu.first_update_at)) <= 24THEN 100ELSE 100 - ((AVG(TIMESTAMPDIFF(HOUR, i.created_at, fu.first_update_at)) - 24)/ 24 * 10)END)) * 0.30 )+ ( ROUND(SUM(CASE WHEN pr.status = 'delivered' THEN 1 ELSE 0 END)/ NULLIF(COUNT(DISTINCT pr.id), 0) * 100, 2) * 0.30 ), 2)                                                                AS overall_scoreFROM  ISSUES iLEFT JOIN (SELECT issue_id, MIN(created_at) AS first_update_atFROM   ISSUE_UPDATESGROUP BY issue_id) fu ON fu.issue_id = i.idLEFT JOIN PROMISES pr ON pr.mp_id = i.mp_idGROUP BY i.mp_idORDER BY overall_score DESC;END $$DROP PROCEDURE IF EXISTS sp_GetConstituencyStats $$CREATE PROCEDURE sp_GetConstituencyStats(IN p_constituency_id INT)BEGINSELECTconstituency_id,COUNT()                                                        AS total_issues,SUM(CASE WHEN status = 'resolved'    THEN 1 ELSE 0 END)        AS resolved_issues,SUM(CASE WHEN status = 'open'        THEN 1 ELSE 0 END)        AS open_issues,SUM(CASE WHEN status = 'in_progress' THEN 1 ELSE 0 END)        AS in_progress_issues,ROUND(SUM(CASE WHEN status = 'resolved' THEN 1 ELSE 0 END)/ NULLIF(COUNT(), 0) * 100, 2)                                                            AS resolution_rate_pct,COUNT(DISTINCT ward_id)                                         AS wards_covered,COUNT(DISTINCT mp_id)                                           AS mp_countFROM  ISSUESWHERE constituency_id = p_constituency_id;END $$DROP PROCEDURE IF EXISTS sp_GetNationalStats $$CREATE PROCEDURE sp_GetNationalStats()BEGINSELECTCOUNT()                                                            AS total_issues_nationwide,SUM(CASE WHEN status = 'resolved'    THEN 1 ELSE 0 END)            AS total_resolved,SUM(CASE WHEN status = 'open'        THEN 1 ELSE 0 END)            AS total_open,SUM(CASE WHEN status = 'in_progress' THEN 1 ELSE 0 END)            AS total_in_progress,ROUND(SUM(CASE WHEN status = 'resolved' THEN 1 ELSE 0 END)/ NULLIF(COUNT(), 0) * 100, 2)                                                                AS national_resolution_rate_pct,COUNT(DISTINCT constituency_id)                                     AS active_constituencies,COUNT(DISTINCT mp_id)                                               AS active_mps,COUNT(DISTINCT ward_id)                                             AS active_wards,ROUND(COUNT(*) / NULLIF(COUNT(DISTINCT mp_id), 0), 1)              AS avg_issues_per_mpFROM  ISSUES;END $$DROP PROCEDURE IF EXISTS sp_GetIssueResolutionRate $$CREATE PROCEDURE sp_GetIssueResolutionRate(IN p_mp_id INT)BEGINSELECTp_mp_id                                                         AS mp_id,COUNT()                                                        AS total_issues,SUM(CASE WHEN status = 'resolved' THEN 1 ELSE 0 END)           AS resolved_issues,ROUND(SUM(CASE WHEN status = 'resolved' THEN 1 ELSE 0 END)/ NULLIF(COUNT(), 0) * 100, 2)                                                            AS resolution_rate_pctFROM  ISSUESWHERE mp_id = p_mp_id;END $$DROP PROCEDURE IF EXISTS sp_GetAverageResponseTime $$CREATE PROCEDURE sp_GetAverageResponseTime(IN p_mp_id INT)BEGINSELECTp_mp_id                                                         AS mp_id,COUNT(DISTINCT i.id)                                            AS issues_with_response,ROUND(AVG(TIMESTAMPDIFF(HOUR, i.created_at, fu.first_update_at)), 2)                                                           AS avg_response_hours,ROUND(AVG(TIMESTAMPDIFF(MINUTE, i.created_at, fu.first_update_at)), 0)                                                           AS avg_response_minutes,MIN(TIMESTAMPDIFF(HOUR, i.created_at, fu.first_update_at))     AS fastest_response_hours,MAX(TIMESTAMPDIFF(HOUR, i.created_at, fu.first_update_at))     AS slowest_response_hoursFROM  ISSUES iJOIN (SELECT issue_id, MIN(created_at) AS first_update_atFROM   ISSUE_UPDATESGROUP BY issue_id) fu ON fu.issue_id = i.idWHERE i.mp_id = p_mp_id;END $$DROP PROCEDURE IF EXISTS sp_GetMonthlyIssueTrend $$CREATE PROCEDURE sp_GetMonthlyIssueTrend(IN p_mp_id  INT,IN p_months INT)BEGINSET p_months = COALESCE(p_months, 12);    SELECT        DATE_FORMAT(created_at, '%Y-%m')                                AS month_label,        YEAR(created_at)                                                AS yr,        MONTH(created_at)                                               AS mo,        COUNT(*)                                                        AS total_issues,        SUM(CASE WHEN status = 'resolved' THEN 1 ELSE 0 END)           AS resolved_issues,        SUM(CASE WHEN status = 'open'     THEN 1 ELSE 0 END)           AS open_issues    FROM  ISSUES    WHERE (p_mp_id IS NULL OR mp_id = p_mp_id)      AND  created_at >= DATE_SUB(CURDATE(), INTERVAL p_months MONTH)    GROUP BY YEAR(created_at), MONTH(created_at),             DATE_FORMAT(created_at, '%Y-%m')    ORDER BY yr ASC, mo ASC;END $$DROP PROCEDURE IF EXISTS sp_GetCategoryBreakdown $$CREATE PROCEDURE sp_GetCategoryBreakdown(IN p_mp_id INT)BEGINSELECTCOALESCE(category, 'Uncategorised')                             AS category,COUNT()                                                        AS total_issues,SUM(CASE WHEN status = 'resolved' THEN 1 ELSE 0 END)           AS resolved_issues,ROUND(SUM(CASE WHEN status = 'resolved' THEN 1 ELSE 0 END)/ NULLIF(COUNT(), 0) * 100, 2)                                                            AS resolution_rate_pctFROM  ISSUESWHERE mp_id = p_mp_idGROUP BY categoryORDER BY total_issues DESC;END $$DROP PROCEDURE IF EXISTS sp_GetWardEngagementStats $$CREATE PROCEDURE sp_GetWardEngagementStats(IN p_mp_id INT)BEGINSELECTward_id,COUNT()                                                             AS total_issues,COUNT(DISTINCT reported_by)                                          AS unique_constituents,SUM(CASE WHEN status = 'resolved'    THEN 1 ELSE 0 END)             AS resolved_issues,SUM(CASE WHEN status = 'open'        THEN 1 ELSE 0 END)             AS open_issues,SUM(CASE WHEN status = 'in_progress' THEN 1 ELSE 0 END)             AS in_progress_issues,ROUND(SUM(CASE WHEN status = 'resolved' THEN 1 ELSE 0 END)/ NULLIF(COUNT(), 0) * 100, 2)                                                                 AS resolution_rate_pct,ROUND(COUNT(*) / NULLIF(COUNT(DISTINCT reported_by), 0), 2)                                                                 AS avg_issues_per_constituentFROM  ISSUESWHERE mp_id = p_mp_idGROUP BY ward_idORDER BY total_issues DESC;END $$CALL sp_GetAllSubscriptionPlans();CALL sp_GetSubscriptionPlan(1);CALL sp_SubscribeMP(100, 2, '2026-04-01', '2027-04-01', @newid);SELECT @newid;CALL sp_InsertPressAccount('Daily Mail Zambia', 'Jane Mwanza', 'jane@daily.co.zm', 'premium', @pid);SELECT @pid;CALL sp_GetExpiringSubscriptions();DELIMITER ;